/**
 * Lender LLPA data loader.
 *
 * Returns lender-specific LLPA adjustments extracted from rate sheet XLSX files.
 * Data is generated by: node scripts/extract-lender-llpas.js
 *
 * Usage:
 *   const { getLenderLLPAs } = require('./src/data/lender-llpas');
 *   const llpas = getLenderLLPAs('everstream');
 *   // llpas.ficoLtvGrids.purchase['≥800'] => [0, 0, 0, 0, 0.375, ...]
 */

const fs = require('fs');
const path = require('path');

const AVAILABLE_LENDERS = ['everstream', 'amwest', 'swmc'];

// Cache loaded data in memory
const cache = {};

/**
 * Load and return LLPA data for a given lender.
 * @param {string} lenderId - One of: 'everstream', 'amwest', 'swmc'
 * @returns {Object|null} Parsed LLPA data, or null if lender not found
 */
function getLenderLLPAs(lenderId) {
  if (!lenderId) return null;
  const id = lenderId.toLowerCase();

  if (cache[id]) return cache[id];

  const filePath = path.join(__dirname, `${id}.json`);
  if (!fs.existsSync(filePath)) return null;

  try {
    const data = JSON.parse(fs.readFileSync(filePath, 'utf8'));
    cache[id] = data;
    return data;
  } catch (e) {
    console.error(`Failed to load LLPA data for ${id}:`, e.message);
    return null;
  }
}

/**
 * List all available lender IDs that have LLPA data.
 * @returns {string[]}
 */
function getAvailableLenders() {
  return AVAILABLE_LENDERS.filter((id) => {
    const filePath = path.join(__dirname, `${id}.json`);
    return fs.existsSync(filePath);
  });
}

module.exports = { getLenderLLPAs, getAvailableLenders };
